package main

import (
	"sort"
)

type UnionFind struct {
	parent []int
	min    []int
}

func NewUnionFind(size int) *UnionFind {
	parent := make([]int, size+1)
	min := make([]int, size+1)
	for i := 1; i <= size; i++ {
		parent[i] = i
		min[i] = i
	}
	return &UnionFind{parent: parent, min: min}
}

func (uf *UnionFind) Find(u int) int {
	if uf.parent[u] != u {
		uf.parent[u] = uf.Find(uf.parent[u])
	}
	return uf.parent[u]
}

func (uf *UnionFind) Union(u, v int) {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU != rootV {
		if rootU < rootV {
			uf.parent[rootV] = rootU
			if uf.min[rootV] < uf.min[rootU] {
				uf.min[rootU] = uf.min[rootV]
			}
		} else {
			uf.parent[rootU] = rootV
			if uf.min[rootU] < uf.min[rootV] {
				uf.min[rootV] = uf.min[rootU]
			}
		}
	}
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	n := int(c)
	uf := NewUnionFind(n)
	for _, conn := range connections {
		u := int(conn[0])
		v := int(conn[1])
		uf.Union(u, v)
	}

	online := make([]bool, n+1)
	for i := 1; i <= n; i++ {
		online[i] = true
	}

	// Preprocess components and their online nodes
	componentNodes := make(map[int][]int)
	for i := 1; i <= n; i++ {
		root := uf.Find(i)
		componentNodes[root] = append(componentNodes[root], i)
	}

	// For each component, maintain a sorted list of online nodes
	componentOnline := make(map[int][]int)
	for root, nodes := range componentNodes {
		onlineNodes := make([]int, 0)
		for _, node := range nodes {
			if online[node] {
				onlineNodes = append(onlineNodes, node)
			}
		}
		sort.Ints(onlineNodes)
		componentOnline[root] = onlineNodes
	}

	result := make([]int64, 0)
	for _, query := range queries {
		typ := query[0]
		x := int(query[1])
		if typ == 1 {
			if online[x] {
				result = append(result, int64(x))
			} else {
				root := uf.Find(x)
				onlineNodes := componentOnline[root]
				if len(onlineNodes) > 0 {
					result = append(result, int64(onlineNodes[0]))
				} else {
					result = append(result, -1)
				}
			}
		} else if typ == 2 {
			if online[x] {
				online[x] = false
				root := uf.Find(x)
				// Find and remove x from componentOnline[root]
				onlineNodes := componentOnline[root]
				idx := sort.SearchInts(onlineNodes, x)
				if idx < len(onlineNodes) && onlineNodes[idx] == x {
					componentOnline[root] = append(onlineNodes[:idx], onlineNodes[idx+1:]...)
				}
			}
		}
	}
	return result
}
