	parent []int
	min    []int
}

func NewUnionFind(size int) *UnionFind {
	parent := make([]int, size+1)
	min := make([]int, size+1)
	for i := 1; i <= size; i++ {
		parent[i] = i
		min[i] = i
	}
	return &UnionFind{parent: parent, min: min}
}

func (uf *UnionFind) Find(u int) int {
	if uf.parent[u] != u {
		uf.parent[u] = uf.Find(uf.parent[u])
	}
	return uf.parent[u]
}

func (uf *UnionFind) Union(u, v int) {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU != rootV {
		if rootU < rootV {
			uf.parent[rootV] = rootU
			if uf.min[rootV] < uf.min[rootU] {
				uf.min[rootU] = uf.min[rootV]
			}
		} else {
			uf.parent[rootU] = rootV
			if uf.min[rootU] < uf.min[rootV] {
				uf.min[rootV] = uf.min[rootU]
			}
		}
	}
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	uf := NewUnionFind(int(c))
	for _, conn := range connections {
		u := int(conn[0])
		v := int(conn[1])
		uf.Union(u, v)
	}

	online := make([]bool, c+1)
	for i := 1; i <= int(c); i++ {
		online[i] = true
	}

	// Precompute component members
	componentMembers := make(map[int][]int)
	for i := 1; i <= int(c); i++ {
		root := uf.Find(i)
		componentMembers[root] = append(componentMembers[root], i)
	}

	// For each component, maintain a sorted list of online members
	componentOnline := make(map[int][]int)
	for root, members := range componentMembers {
		sort.Ints(members)
		onlineMembers := make([]int, 0)
		for _, m := range members {
			if online[m] {
				onlineMembers = append(onlineMembers, m)
			}
		}
		componentOnline[root] = onlineMembers
	}

	result := make([]int64, 0)
	for _, query := range queries {
		typ := query[0]
		x := int(query[1])
		if typ == 1 {
			if online[x] {
				result = append(result, int64(x))
			} else {
				root := uf.Find(x)
				onlineMembers := componentOnline[root]
				if len(onlineMembers) > 0 {
					result = append(result, int64(onlineMembers[0]))
				} else {
					result = append(result, -1)
				}
			}
		} else if typ == 2 {
			if online[x] {
				online[x] = false
				root := uf.Find(x)
				// Find x in componentOnline[root] and remove it
				onlineMembers := componentOnline[root]
				idx := sort.SearchInts(onlineMembers, x)
				if idx < len(onlineMembers) && onlineMembers[idx] == x {
					componentOnline[root] = append(onlineMembers[:idx], onlineMembers[idx+1:]...)
				}
			}
		}
	}
	return result
}
