package main

import (
	"sort"
)

type UnionFind struct {
	parent []int64
	min    []int64
}

func NewUnionFind(size int64) *UnionFind {
	parent := make([]int64, size+1)
	min := make([]int64, size+1)
	for i := int64(1); i <= size; i++ {
		parent[i] = i
		min[i] = i
	}
	return &UnionFind{parent: parent, min: min}
}

func (uf *UnionFind) Find(u int64) int64 {
	if uf.parent[u] != u {
		uf.parent[u] = uf.Find(uf.parent[u])
	}
	return uf.parent[u]
}

func (uf *UnionFind) Union(u, v int64) {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU != rootV {
		if rootU < rootV {
			uf.parent[rootV] = rootU
			if uf.min[rootV] < uf.min[rootU] {
				uf.min[rootU] = uf.min[rootV]
			}
		} else {
			uf.parent[rootU] = rootV
			if uf.min[rootU] < uf.min[rootV] {
				uf.min[rootV] = uf.min[rootU]
			}
		}
	}
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	uf := NewUnionFind(c)
	for _, conn := range connections {
		u, v := conn[0], conn[1]
		uf.Union(u, v)
	}

	online := make([]bool, c+1)
	for i := int64(1); i <= c; i++ {
		online[i] = true
	}

	// To efficiently track the min online in each component, we'll use a map of component root to a sorted list of online nodes
	componentNodes := make(map[int64][]int64)
	for i := int64(1); i <= c; i++ {
		root := uf.Find(i)
		componentNodes[root] = append(componentNodes[root], i)
	}

	// Sort the nodes in each component
	for root := range componentNodes {
		sort.Slice(componentNodes[root], func(i, j int) bool {
			return componentNodes[root][i] < componentNodes[root][j]
		})
	}

	result := []int64{}
	for _, query := range queries {
		typ, x := query[0], query[1]
		if typ == 1 {
			if online[x] {
				result = append(result, x)
			} else {
				root := uf.Find(x)
				nodes := componentNodes[root]
				minOnline := int64(-1)
				// Binary search for the smallest online node in the component
				left, right := 0, len(nodes)-1
				for left <= right {
					mid := (left + right) / 2
					if online[nodes[mid]] {
						minOnline = nodes[mid]
						right = mid - 1
					} else {
						left = mid + 1
					}
				}
				result = append(result, minOnline)
			}
		} else if typ == 2 {
			online[x] = false
		}
	}
	return result
